class BackgroundTaskService : IntentService("Background Task Service") {
    override fun onHandleIntent(intent: Intent?) {
        val task = intent?.getStringExtra("task_type") ?: ""
        
        when (task) {
            "cleanup" -> cleanUpData()
            
            else ->  runTaskInBackgroundAndNotifyMeAboutProgressOrCompletionIfRequired(intent, 0.5f ) // default progress is set to halfway point of the range [0..1] for demonstration purposes only (this could be any value you wish)  
        }        
    }    
